  2→ * Linear OAuth 2.0 implementation with PKCE.
  3→ *
  4→ * Handles the full auth-code flow (authorize URL generation, callback exchange)
  5→ * and automatic token refresh.
  6→ */
  7→import { getDb } from "../be/db";
  8→import type { LinearOAuthToken, LinearTokenResponse, PendingOAuthState } from "./types";
  9→
 10→// ---------------------------------------------------------------------------
 11→// Constants
 12→// ---------------------------------------------------------------------------
 13→
 14→const LINEAR_AUTHORIZE_URL = "https://linear.app/oauth/authorize";
 15→const LINEAR_TOKEN_URL = "https://api.linear.app/oauth/token";
 16→const OAUTH_SCOPES =
 17→  "read,write,issues:create,comments:create,admin,app:assignable,app:mentionable";
 18→
 19→// In-memory map of state → code_verifier (short-lived, cleaned up on callback)
 20→const pendingStates = new Map<string, PendingOAuthState>();
 21→
 22→// Expire pending states after 10 minutes
 23→const PENDING_STATE_TTL_MS = 10 * 60 * 1000;
 24→
 25→// ---------------------------------------------------------------------------
 26→// PKCE helpers
 27→// ---------------------------------------------------------------------------
 28→
 29→function generateRandomString(length: number): string {
 30→  const array = new Uint8Array(length);
 31→  crypto.getRandomValues(array);
 32→  return Array.from(array)
 33→    .map((b) => b.toString(16).padStart(2, "0"))
 34→    .join("")
 35→    .slice(0, length);
 36→}
 37→
 38→async function sha256(plain: string): Promise<ArrayBuffer> {
 39→  const encoder = new TextEncoder();
 40→  return crypto.subtle.digest("SHA-256", encoder.encode(plain));
 41→}
 42→
 43→function base64url(buffer: ArrayBuffer): string {
 44→  const bytes = new Uint8Array(buffer);
 45→  let binary = "";
 46→  for (const b of bytes) {
 47→    binary += String.fromCharCode(b);
 48→  }
 49→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
 50→}
 51→
 52→async function generateCodeChallenge(codeVerifier: string): Promise<string> {
 53→  const hash = await sha256(codeVerifier);
 54→  return base64url(hash);
 55→}
 56→
 57→// ---------------------------------------------------------------------------
 58→// Authorization URL
 59→// ---------------------------------------------------------------------------
 60→
 61→export async function getAuthorizationUrl(): Promise<string> {
 62→  const clientId = process.env.LINEAR_CLIENT_ID;
 63→  const redirectUri = process.env.LINEAR_REDIRECT_URI;
 64→
 65→  if (!clientId || !redirectUri) {
 66→    throw new Error("[Linear] LINEAR_CLIENT_ID and LINEAR_REDIRECT_URI must be set");
 67→  }
 68→
 69→  // Clean up expired pending states
 70→  const now = Date.now();
 71→  for (const [key, val] of pendingStates) {
 72→    if (now - val.createdAt > PENDING_STATE_TTL_MS) {
 73→      pendingStates.delete(key);
 74→    }
 75→  }
 76→
 77→  const codeVerifier = generateRandomString(64);
 78→  const codeChallenge = await generateCodeChallenge(codeVerifier);
 79→  const state = generateRandomString(32);
 80→
 81→  pendingStates.set(state, { codeVerifier, createdAt: now });
 82→
 83→  const params = new URLSearchParams({
 84→    client_id: clientId,
 85→    redirect_uri: redirectUri,
 86→    response_type: "code",
 87→    scope: OAUTH_SCOPES,
 88→    code_challenge: codeChallenge,
 89→    code_challenge_method: "S256",
 90→    state,
 91→  });
 92→
 93→  return `${LINEAR_AUTHORIZE_URL}?${params.toString()}`;
 94→}
 95→
 96→// ---------------------------------------------------------------------------
 97→// OAuth callback — exchange code for tokens
 98→// ---------------------------------------------------------------------------
 99→
100→export async function handleOAuthCallback(code: string, state: string): Promise<void> {
101→  const pending = pendingStates.get(state);
102→  if (!pending) {
103→    throw new Error("[Linear] Invalid or expired OAuth state parameter");
104→  }
105→  pendingStates.delete(state);
106→
107→  const clientId = process.env.LINEAR_CLIENT_ID;
108→  const clientSecret = process.env.LINEAR_CLIENT_SECRET;
109→  const redirectUri = process.env.LINEAR_REDIRECT_URI;
110→
111→  if (!clientId || !clientSecret || !redirectUri) {
112→    throw new Error(
113→      "[Linear] LINEAR_CLIENT_ID, LINEAR_CLIENT_SECRET, LINEAR_REDIRECT_URI must be set",
114→    );
115→  }
116→
117→  const response = await fetch(LINEAR_TOKEN_URL, {
118→    method: "POST",
119→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
120→    body: new URLSearchParams({
121→      grant_type: "authorization_code",
122→      client_id: clientId,
123→      client_secret: clientSecret,
124→      redirect_uri: redirectUri,
125→      code,
126→      code_verifier: pending.codeVerifier,
127→    }),
128→  });
129→
130→  if (!response.ok) {
131→    const text = await response.text();
132→    throw new Error(`[Linear] Token exchange failed (${response.status}): ${text}`);
133→  }
134→
135→  const data = (await response.json()) as LinearTokenResponse;
136→  await storeTokens(data);
137→  console.log("[Linear] OAuth tokens stored successfully");
138→}
139→
140→// ---------------------------------------------------------------------------
141→// Token refresh
142→// ---------------------------------------------------------------------------
143→
144→export async function refreshAccessToken(): Promise<LinearOAuthToken | null> {
145→  const tokens = getStoredTokens();
146→  if (!tokens) {
147→    console.warn("[Linear] No stored tokens to refresh");
148→    return null;
149→  }
150→
151→  const clientId = process.env.LINEAR_CLIENT_ID;
152→  const clientSecret = process.env.LINEAR_CLIENT_SECRET;
153→
154→  if (!clientId || !clientSecret) {
155→    console.warn("[Linear] Cannot refresh — missing CLIENT_ID or CLIENT_SECRET");
156→    return null;
157→  }
158→
159→  const response = await fetch(LINEAR_TOKEN_URL, {
160→    method: "POST",
161→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
162→    body: new URLSearchParams({
163→      grant_type: "refresh_token",
164→      client_id: clientId,
165→      client_secret: clientSecret,
166→      refresh_token: tokens.refreshToken,
167→    }),
168→  });
169→
170→  if (!response.ok) {
171→    const text = await response.text();
172→    console.error(`[Linear] Token refresh failed (${response.status}): ${text}`);
173→    return null;
174→  }
175→
176→  const data = (await response.json()) as LinearTokenResponse;
177→  return storeTokens(data);
178→}
179→
180→// ---------------------------------------------------------------------------
181→// Token storage (DB)
182→// ---------------------------------------------------------------------------
183→
184→export function getStoredTokens(): LinearOAuthToken | null {
185→  const db = getDb();
186→  const row = db.query("SELECT * FROM linear_oauth_tokens ORDER BY createdAt DESC LIMIT 1").get();
187→  return (row as LinearOAuthToken) ?? null;
188→}
189→
190→export function isTokenExpiringSoon(expiresAt: string, bufferMs = 5 * 60 * 1000): boolean {
191→  const expiryTime = new Date(expiresAt).getTime();
192→  return Date.now() + bufferMs >= expiryTime;
193→}
194→
195→async function storeTokens(data: LinearTokenResponse): Promise<LinearOAuthToken> {
196→  const db = getDb();
197→  const expiresAt = new Date(Date.now() + data.expires_in * 1000).toISOString();
198→  const now = new Date().toISOString();
199→
200→  // Upsert: delete all existing rows, insert the new one (single-row table)
201→  // Wrapped in a transaction to ensure atomicity
202→  const store = db.transaction(() => {
203→    db.run("DELETE FROM linear_oauth_tokens");
204→    db.run(
205→      `INSERT INTO linear_oauth_tokens (accessToken, refreshToken, expiresAt, scope, createdAt, updatedAt)
206→       VALUES (?, ?, ?, ?, ?, ?)`,
207→      [
208→        data.access_token,
209→        data.refresh_token ?? "",
210→        expiresAt,
211→        data.scope ?? OAUTH_SCOPES,
212→        now,
213→        now,
214→      ],
215→    );
216→  });
217→  store();
218→
219→  return getStoredTokens()!;
220→}
